import{_ as a,o as t,c as b,j as r,a as s,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"流陨","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/流陨.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/流陨.md"}'),o={name:"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/流陨.md"};function d(p,e,l,i,_,c){return t(),b("div",null,[...e[0]||(e[0]=[r("h1",{id:"流陨",tabindex:"-1"},[s("流陨 "),r("a",{class:"header-anchor",href:"#流陨","aria-label":'Permalink to "流陨"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌034")])])],-1),n('<h1 id="流陨-1" tabindex="-1">流陨 <a class="header-anchor" href="#流陨-1" aria-label="Permalink to &quot;流陨&quot;">​</a></h1><p>流陨<br> 特异本质<br> 【该武器需要逐级购买升级，若无特殊情况，购买高等级后保留低等级武器效果。】<br> D级<br> 价格：D+500<br> 概述：一把或者说一杆铁枪杆，它看起来跟一根铁棍没啥两样，只有显现的时候，两端会出现一大一小两束锥形光束。<br> 这把武器从是某个时空内出现的，是某种可能性之一。<br> 分类：枪<br> 体积：4<br> 基础：6L<br> 特殊：【双手】【长柄】【格挡2】<br> 特性：<br> 【概念武装】你购买该武器时，需要经历三天的可能性融合，你可能会记忆混乱，或者做一些奇怪的事，但在此之后它便认你为主，你可以随时显现出它真正的形态，其他人拿起这把武器的时候，只能当作2L武器伤害的长棍来使用。<br> 【光枪】你使用这把武器攻击时造成光能伤害。<br> 【无尽狩猎】你进入战斗后，每经历一回合，以该武器进行的攻击可以额外获得1点高速，可无限叠加，这些额外的高速会因战斗结束而消失。<br> （ps:无法跟蚂蚁进行战斗等……）</p><p>C级<br> 价格：C+1000<br> 描述：这把长枪材质变成了黑色玉石材质，我说的是枪杆部分，枪口处有一条飞龙攀附而上，光刃从龙口吐出，并且伸缩光刃似乎更为凝实了，变成了扭曲的蓝色枪刃。<br> 分类：枪<br> 体积：4<br> 基础：14L<br> 特殊：【双手】【长柄】【格挡2】<br> 特性：<br> 【狩猎血渴】强大的实力是狩猎的前提，狩猎吸收这是永恒不变的旋律……每轮一次，当你某个目标时，你可以在下个回合行动之前将对方的基础防御减少5点，同时你获得对方基础防御所基于的防御类型的5点防御，若你在一次攻击中命中多个敌人，则选择其中一位生效，这视为该武器等级的创伤来源效果。</p><p>B级<br> 价格：B+2000<br> 描述：现在，这柄长枪开始展露自己的真容，整枪覆盖上了各种强大的生物凝结的黑色结晶，枪刃处的光仿佛已经化为实质，在边上融入了黑色的利维坦甲壳，随着某种节奏，它似乎在呼吸，并且散发着微弱的光，这把武器似乎开始有了……生命。<br> 分类：枪<br> 体积：4<br> 基础：21L<br> 特殊：【双手】【长柄】【格挡2】<br> 特性：<br> 【龙枪形态】你使用时，可以以一个自由动作展开武器进入龙枪模式。龙枪模式下，你的武器体积变成7，枪刃完全展开，释放恐怖的热能，你攻击获得【8加骰】和2dp增强加值。<br> 如果目标被攻击命中，你可以选择只造成一半伤害，将另一半的伤害作为【龙焰】封存于对方体内，每轮只能叠加一层【龙焰】，最高可以叠加到10层。你也可以提前声明，随后在你回合内对目标攻击来引爆【龙焰】，每层【龙焰】均需单独结算伤害。<br> 如果战斗结束或者你死亡了，那么龙焰将会被提前引爆，或者最迟在15分钟内生效，否则将渐渐熄灭，同样的这种方法在你范围内每个目标只能生效一次。<br> 同时只要被攻击到或者身上拥有【龙焰】，则可能性被封死，该目标无法用B级及以下的传送。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',6)])])}const m=a(o,[["render",d]]);export{f as __pageData,m as default};
